#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv3d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    // Output shape: [N, Co, D-Kd+1, H-Kh+1, W-Kw+1]
    TORCH_CHECK(x.dim() == 5, "x must be 5D [N,C,D,H,W]");
    TORCH_CHECK(weight.dim() == 5, "weight must be 5D [Co,C,Kd,Kh,Kw]");
    TORCH_CHECK(x.size(1) == weight.size(1), "Input C must match weight C");
    auto N = x.size(0);
    auto Co = weight.size(0);
    auto Do = x.size(2) - weight.size(2) + 1;
    auto Ho = x.size(3) - weight.size(3) + 1;
    auto Wo = x.size(4) - weight.size(4) + 1;
    TORCH_CHECK(Do > 0 && Ho > 0 && Wo > 0, "Invalid shapes for valid conv3d");

    at::Tensor y = at::empty({N, Co, Do, Ho, Wo}, x.options());
    EXEC_NPU_CMD(aclnnConvStandard3dAsymmetricInputAsymmetricKernelCustom, x, weight, y);
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv_standard_3d_asymmetric_input_asymmetric_kernel_custom", &conv3d_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("conv_standard_3d_asymmetric_input_asymmetric_kernel_custom",
          &conv3d_impl_npu,
          "Conv3d valid stride1 (ConvStandard3dAsymmetricInputAsymmetricKernelCustom on NPU)");
}
